    }
    if let Some(value) = id.strip_prefix(ARCHIVE_PATCHER_RESTORE_TASK_PREFIX) {
        return value
            .parse::<ArchivePatcherRequestId>()
            .ok()
            .map(|request_id| (ArchivePatcherWorkerStage::Restore, request_id));
